269: 	var allErrs field.ErrorList
270: 	switch deviceAllocationMode {
271: 	case resource.DeviceAllocationModeAll:
272: 		if count != 0 {
273: 			allErrs = append(allErrs, field.Invalid(countFldPath, count, fmt.Sprintf("must not be specified when allocationMode is '%s'", deviceAllocationMode)))
274: 		}
275: 	case resource.DeviceAllocationModeExactCount:
276: 		if count <= 0 {
277: 			allErrs = append(allErrs, field.Invalid(countFldPath, count, "must be greater than zero"))
278: 		}
279: 	default:
280: 		// NOTE: Declarative validation does not (yet) enforce the real requiredness of this field
281: 		// because v1beta1 uses a bespoke form of union which makes this field truly optional
282: 		// in some cases and truly required in others. DO NOT REMOVE THIS CODE UNLESS THAT IS RESOLVED.
283: 		allErrs = append(allErrs, field.NotSupported(allocModeFldPath, deviceAllocationMode, []resource.DeviceAllocationMode{resource.DeviceAllocationModeAll, resource.DeviceAllocationModeExactCount}).MarkCoveredByDeclarative())
284: 	}
285: 	return allErrs
286: }
